var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"이것은 대정화전쟁 이후 유래 없는 피해입니다.","JPN":"今回の被害の規模は、大浄化戦争以来最大だと言われています。","ENG":"This is the worst damage since the Grand Purification War.","TWN":"這是自大淨化戰爭以來前所未有的災難。"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"먹구름은 물러갔으나 관리국마저 대처하지 못한 현 사태에 대해, 거주민 대다수가 상대적으로 안전한 관리구역으로 이주 절차를 신청한 것으로…","JPN":"墨雲は消えたものの、管理局ですら対処できなかった現状に対し、多くの居住者が比較的安全な管理区域への移住手続きを申し込んでおり……","ENG":"Though the dark clouds have cleared, the Administration failed to respond in time. Most residents have already applied to relocate to safer managed zones under its jurisdiction…","TWN":"墨雨雖然退去，但面對管理局都無法應對的現狀，大多數居民都申請了相對安全的管理區移民…"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L6_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"먹비가 그쳤군.","JPN":"墨雨が止んだな。","ENG":"The Ink Rain stopped.","TWN":"墨雨停了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"對。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"관리국 덕에 도시는 최소한의 피해로 역경을 무사히 넘겼어.","JPN":"管理局のおかげで都市は被害を最小限に抑え、無事危機を乗り越えた。","ENG":"The city made it through with minimal damage.","TWN":"城市以最小的損失，平安度過了這次難關。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 아이가 먼 거리를 달려 우릴 찾아오지 않았다면… 우린 아직 도시에 이런 재난이 벌어진 줄도 몰랐겠지.","JPN":"あの子が遠い距離を走って私たちのところに来ていなかったら……いまだ都市に災害が訪れたことすら知らずにいただろう。","ENG":"If that girl hadn't run all that way to find us… We wouldn't have known a disaster had even struck in the city.","TWN":"如果那個孩子沒有跑到這麼遠的地方來找我們…我們可能還不知道城裡發生了這樣的災難。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"문득 궁금해지는군.","JPN":"突然気になってきたのだが。","ENG":"Makes me wonder.","TWN":"我突然感到好奇。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"과거를 바꾸어 세상에 먹비의 존재를 없앤다면, 오늘 있었던 일도 없던 것이 될지.","JPN":"過去を変えてこの世から墨雨を消し去ることができたら、今日の災害もなかったことになるのだろうか。","ENG":"If we manage to change the past and erase the Ink Rain from history, does that mean today's disaster never happened?","TWN":"如果改變過去，讓世界上不再有墨雨，那今天發生的災難也會變成沒發生過嗎？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그건 모를 일이지.","JPN":"それは分からないさ。","ENG":"Who knows?","TWN":"這就不知道了。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"누구도 그렇게 해본 적이 없으니까.","JPN":"誰もやったことがないからな。","ENG":"No one's ever done it before.","TWN":"因為沒有人這麼做過。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"서연이 네가… 연구소 분들을 모셔왔다고? 그 다리로?","JPN":"シュエン、キミが……研究所の人たちをつれて来たの？　その脚で？","ENG":"Seoyeon… you brought the researchers here? With your legs?","TWN":"書妍，你…帶研究室的人過來的？用那雙腿？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"응.","JPN":"うん。","ENG":"Yes.","TWN":"嗯。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"내가… 비 내리지 않는 곳으로 도망치라고 했잖아!","JPN":"ボクが……雨が降らない場所に逃げろって言っただろ！","ENG":"But… I told you to run away from the rain!","TWN":"我…不是叫你逃到沒有下雨的地方嗎！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"근데 왜 도망치지 않은 거야!","JPN":"なんですぐ逃げなかったんだよ！","ENG":"Why'd you go there?!","TWN":"但你為什麼去那裡！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"동월이 네가 모두를 도우려고 여기 남았으니까…","JPN":"トウゲツはみんなを助けるために残ったんだから……","ENG":"Just like you stayed behind to protect the kids at the orphanage, Dongwol…","TWN":"就像佟月為了保護保育院的孩子們而留下…"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"나도… 너한테 도움이 되고 싶었어.","JPN":"アタシも、キミの力になりたかった。","ENG":"I never planned to run away either.","TWN":"我從一開始就沒想過要逃跑。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"도망치는 것보다 더 중요한 게… 여기 있으니까.","JPN":"逃げるより……もっと大事なものがあったから。","ENG":"Some things… matter more than running.","TWN":"因為…有比逃跑更重要的事情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"그래서 다행이야.","JPN":"だからよかった。","ENG":"That's why I'm relieved.","TWN":"所以太好了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"네가 무사해서.","JPN":"トウゲツが無事で、よかったよ。","ENG":"I'm relieved you're safe.","TWN":"你平安無事，真是太好了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"그치만 나 때문에 네 눈이…","JPN":"うっ……ボクのせいでシュエンの目が……","ENG":"*Sniffle…* Because of me, your eyes…","TWN":"嗚…都怪我，你的眼睛…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"왜… 그런 거야! 왜 나 때문에 네가…!","JPN":"なんで……なんでだ！　なんでボクのせいでシュエンが……！","ENG":"Why'd you do it…?! Because of me…!","TWN":"為什麼…會這樣！為什麼你為了我…！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"네 얼굴… 만져봐도 돼?","JPN":"顔……触ってもいい？","ENG":"Can I… touch your face?","TWN":"你的臉…可以讓我摸摸嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"나 때문이야… 내가 널 지켜줄 수만 있었어도…","JPN":"ボクのせいだ……ボクが、シュエンを守れたら……","ENG":"If I… could've just protected you…","TWN":"都怪我…如果我能保護你…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"바보. 그게 왜 너 때문이야.","JPN":"バカ。トウゲツのせいなんかじゃないよ。","ENG":"Dummy. How could this be your fault?","TWN":"笨蛋。這怎麼能怪你。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"전부 내가 결정한 일인데.","JPN":"全部アタシが選んだことだもん。","ENG":"Everything that happened was my choice.","TWN":"這全是我自己做的選擇。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"미안… 미안해…","JPN":"ごめん……ごめん……","ENG":"I'm sorry… I'm so sorry…","TWN":"對不起…對不起…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"네가 무사하면 그걸로 된 거야.","JPN":"トウゲツが無事ならそれでいいの。","ENG":"It's enough that you're okay.","TWN":"你平安就夠了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"그러니까, 울지 마.","JPN":"だから泣かないで。","ENG":"So don't cry.","TWN":"所以，別哭。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"서연이는 일반인 치곤 침식내성이 굉장한 편입니다.","JPN":"シュエンは一般人にしては侵食耐性が高いほうです。","ENG":"For a civilian, Seoyeon's incredibly resistant to Corruption.","TWN":"書妍的侵蝕抗性，在一般人中算是非常強的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"하지만 그렇게 먹비에 노출되고도 살아남은 건, 기적이라고 밖에 볼 수 없네요.","JPN":"ですが、あれほど墨雨に晒されて生き残れたのは、奇跡としか言いようがありません。","ENG":"But surviving direct exposure to the Ink Rain is nothing short of a miracle.","TWN":"但即使暴露在墨雨中還能活下來，也只能說是奇蹟。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그 기적으로… 시력을 회복할 가능성은 없는 건가요?","JPN":"その奇跡で……視力を回復する可能性はないんですか？","ENG":"So even with that miracle… there's no hope of her regaining her sight?","TWN":"那這個奇蹟…有沒有可能讓視力恢復？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"한 번 시작된 침식을 돌이킬 방법은 없습니다.","JPN":"一度侵食が始まると、元に戻る方法はありません。","ENG":"There's no known way to reverse the Corruption once it begins.","TWN":"一旦開始被侵蝕，就沒有恢復的辦法。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"늦든 빠르든, 신체의 나머지 부분도 그 영향을 받겠죠.","JPN":"遅かれ早かれ、体の残りの部分にも影響が及ぶでしょう。","ENG":"Sooner or later, the rest of her body will start to show symptoms too.","TWN":"遲早，身體的其他部分也會受到影響。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"지워진 기억이 나날이 선명해지는 건… 그날의 먹구름이 드리운 그늘이 너무나 짙었기 때문일 걸세.","JPN":"消された記憶が日々鮮明になっていくのは……あの日雲が作り出した影があまりにも濃かったからであろう。","ENG":"Memories I'd forgotten only grow sharper… Perhaps because the shadow cast by that day's dark clouds was far too deep.","TWN":"記憶日漸清晰…是因為那天墨雲籠罩的陰影太過濃重。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"과거의 난 소중한 것을 잃고, 그 상실을 등진 채로 도망쳤으나…","JPN":"過去の某は大切なものを失い、その喪失に背を向けて逃げたが……","ENG":"Back then, I ran from my grief. I turned my back on what I'd lost…","TWN":"過去的我失去了重要的東西，然後背棄了那份失落，選擇逃避…"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"저 하늘의 검은 구름은 여전히 우리의 삶을 좀먹어가고 있다네.","JPN":"あの空の黒い雲は依然として我らの生を蝕んでいる。","ENG":"But that black cloud still hangs over our world, slowly gnawing away at it.","TWN":"但天上的墨雲依然在蠶食著我們的生活。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇게 언젠간, 그 그늘에 완전히 삼켜지게 되겠지.","JPN":"そしていずれはその影にすべて呑み込まれてしまうであろう。","ENG":"And one day, it'll swallow us whole.","TWN":"最終，總有一天會被那片陰影徹底吞噬。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"겁쟁이처럼 고개를 파묻어 본들, 그늘을 피할 길은 없을 테니.","JPN":"臆病者のように穴を掘って隠れたとて、影から逃げる術はあるまい。","ENG":"Even if we dig a hole and cower in it, there's no escaping the dark.","TWN":"即使像懦夫一樣躲進洞穴，也無處可逃。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"결국, 내가 매듭을 지어야만 끝날 일이란 걸세.","JPN":"結局、某がけじめをつけるまでは終わらぬということだ。","ENG":"In the end, I have to be the one to end this.","TWN":"終究，這件事必須由我來做個了斷。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…틀린 말은 아니군.","JPN":"……一理ある話だな。","ENG":"…You're not wrong.","TWN":"…說得也沒錯。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"거슬러 올라가면 이 모든 재난의 근원은 결국, 그 범이란 존재에 있으니까.","JPN":"元はと言えば、この災害のすべての根はあの虎という存在にあるのだから。","ENG":"If you trace it all back, every disaster leads to that Tiger.","TWN":"追根究底，所有這些災難的根源，都在於那個叫老虎的存在。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"더는 먹비가 내리지 않도록… 사부는 범이란 녀석을 없애고 싶은 거지?","JPN":"もう墨雨が降らないように……師匠はその虎ってやつを倒したいんでしょ？","ENG":"So you want to get rid of the Tiger… to stop the Ink Rain from falling again, don’t you, Master?","TWN":"為了讓墨雨不再降臨…師父你想要消滅那個叫老虎的傢伙嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"성공할 가능성이 얼마나 되는데?","JPN":"成功する可能性はどれぐらい？","ENG":"What are the odds you will actually succeed?","TWN":"成功的可能性有多高？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"알 수 없네. 굳이 가늠하자면, 실패할 확률이 더 높겠지.","JPN":"分からん。敢えて言うなら……失敗する確率のほうが高いだろう。","ENG":"No idea. If I had to guess, odds are I'll likely fail.","TWN":"我不知道。如果非要衡量，失敗的機率更高。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그럼에도…","JPN":"それでも……","ENG":"But even so…","TWN":"即便如此…"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"더는 외면하고 싶지 않을 뿐이야.","JPN":"これ以上目を逸らしたくはない、それだけだ。","ENG":"I just don't want to look away anymore.","TWN":"我只是不想再逃避了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"몰라. 이제 사부 맘대로 해.","JPN":"もう知らない。師匠の好きにして。","ENG":"Whatever. Do whatever you want now.","TWN":"我不知道了。師父你隨心所欲吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"나도 내 방식대로 할 거니까.","JPN":"私も私のやり方でいくから。","ENG":"I'll handle things my own way.","TWN":"我也會用我自己的方式。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"어렵사리 허락은 받아냈군.","JPN":"なんとか許可は得られたな。","ENG":"Well, I suppose that counts as permission.","TWN":"好不容易獲得了允許。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"허락이 아니라 방조 아닌가?","JPN":"あれは許可じゃなくて放棄じゃないか？","ENG":"More like passive consent.","TWN":"這不是允許，是放任吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"적어도 멱살을 잡히진 않았잖나.","JPN":"少なくとも胸ぐらを掴まれずには済んだではないか。","ENG":"At least she didn't try to strangle me.","TWN":"至少我沒有被抓住領子。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"열차를 멈추지 않으면 계속 희생자가 생긴다는 건, 그 녀석도 알고 있으니까.","JPN":"列車を止めないと犠牲者が増えるだけだということは、あいつも分かっている。","ENG":"She knows. If you don't stop the train, more people will keep getting hurt.","TWN":"因為那個傢伙也知道，如果不停下那輛列車，就會不斷有犧牲者出現。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"하지만 몸을 던져 그 열차를 멈추는 역할을 내게 정말 소중한 사람이 맡아야 한다면… 누구라도 그런 반응일 거다.","JPN":"だが、身を投げてその列車を止める役割をやらねばならないのが、自分の大切な人だとしたら……誰でもああいう反応をするだろう。","ENG":"But if the one who jumps in front of that train is someone you really care about… anyone would react the same.","TWN":"但如果那個為了停下列車而犧牲的人，是她真正重要的人…任何人的反應都會是那樣。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"하담!","JPN":"カタン！","ENG":"Ha Dam!","TWN":"夏垣！"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"첫눈이 펑펑 내리는데, 여태 연구만 하고 있어?","JPN":"せっかくの初雪なのに、まだ研究ばかりしてるの？","ENG":"It's the first snow of the year and you're still buried in research?","TWN":"鵝毛大雪紛飛，你還在搞研究？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"당연하지 않은가. 프로토타입의 시험 가동이 바로 내일이니 말일세.","JPN":"当然ではないか。明日プロトタイプのテスト稼働を控えておるゆえ。","ENG":"Of course I am. The prototype trial run is tomorrow.","TWN":"當然。因為原型機的試運轉就在明天。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그래서?","JPN":"それで？","ENG":"So?","TWN":"然後呢？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"그래서라니…","JPN":"それで、とは……","ENG":"What do you mean \\"so\\"…?","TWN":"然後什麼…"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"전생의 본인이 <color=#ffd34c>나전 천갑</color>을 만들어 과거의 짐승을 현재에 이르지 못하게 막아왔으나, 그 효력도 조만간 다할 거요.","JPN":"前世の某が<color=#ffd34c>螺鈿天甲</color>を作り、過去のケモノが現在に辿り着けないよう防いで来たのだが、その効果も近いうちに切れるだろう。","ENG":"In my past life, I created the <color=#ffd34c>Heavenly Inlaid Armor</color> to stop the Beast from crossing over. But its effects will fade soon.","TWN":"前世的自己製造了<color=#ffd34c>螺鈿天甲</color>，阻止了過去的野獸來到現在，但其效力也將很快消失。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"과거에 머무는 범이 10년 안으로 현실에 들이닥칠 것이라 명달 대장이 염려했으니, 우리는 범보다 먼저 과거로 가 놈을 토벌하는 것만이 뾰족한 수일세.","JPN":"過去に留まっている虎が、あと10年の内に現実を襲うとアカタツ隊長は憂いていた。我らは虎が動くよりも先に過去に到達し、やつを討つしかなかろう。","ENG":"Commander Myeongdal believes the Tiger, still trapped in the past, will emerge within ten years. So the only option is to beat it to the punch. Go back first, and end it.","TWN":"明達隊長擔心，停留在過去的老虎將在十年內侵襲現實，所以我們唯一的辦法就是比老虎先一步回到過去討伐牠。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"그것을 위해 먹비를 응용하는 장치를 개발하여 직접 과거로 가려는 것인데…","JPN":"そのため墨雨を応用する装置を開発し、過去へ向かうつもりだが……","ENG":"That's why I'm repurposing the Ink Rain to develop a device that lets me travel to the past directly…","TWN":"為此，我們開發了應用墨雨的裝置，準備親自回到過去…"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"얍!","JPN":"やっ！","ENG":"Hyup!","TWN":"呀嚇！"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_WIND_03"},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"…갑자기 사람 얼굴에 눈덩이는 왜 던지는 거요?","JPN":"……なぜ突然人の顔に雪玉を投げる？","ENG":"…Did you just hit me in the face with a snowball?","TWN":"…為什麼突然朝人臉扔雪球？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"방구석에서 공부만 하는 서생은 눈싸움이란 것도 모르나 봐?","JPN":"閉じこもって勉強ばかりの学者さんは、雪合戦も知らないのかしら？","ENG":"Guess that bookworm brain of yours doesn't even know how to have a snowball fight.","TWN":"在房間裡只知道讀書的書生，連打雪仗都不懂嗎？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"내 말은 왜 꼭 바쁜 때에 방해를 하냐는… 읍!","JPN":"某の言いたいことは、なぜ忙しい時に限って邪魔をす……うぶっ！","ENG":"Why would you always interrupt me when I'm busy… Mmph!","TWN":"為什麼偏偏要在我忙的時候打擾… 唔！"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"연구는 내일도 할 수 있지만, 눈싸움은 눈이 다 녹으면 못하잖아.","JPN":"研究は明日でもできるけど、雪合戦は雪が溶けたらできないでしょう。","ENG":"You can work tomorrow, but once the snow melts, snowball fights are over.","TWN":"研究明天也可以做，但雪都融化了就不能打雪仗了。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그러니까 즐길 수 있을 때… 읍!","JPN":"だから、楽しめる内に……うっ！","ENG":"So we should enjoy it while we… Mmph!","TWN":"所以要在能享受的時候… 唔！"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"최강의 전사를 스승으로 둔 사람치곤 볼품없게 맞았군.","JPN":"最強の戦士の弟子にしては無様に当てられたな。","ENG":"Not very impressive, considering your master's the strongest warrior around.","TWN":"作為最強戰士的徒弟，被打得如此狼狽。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"앗, 스승님의 명예가 걸려버리면- 나 더는 못 봐주는데?","JPN":"あっ、師匠の名誉をかけられたら……手が抜けなくなるけど？","ENG":"Oh no, you didn't. You had to bring up my master's honor? I can't go easy on you now.","TWN":"如果關係到師父的名譽，我就不能再對你手下留情了！"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"자신 있으면 내기라도 하는 게 어떤가?","JPN":"自信があるなら賭けてみるか？","ENG":"If you're so confident, how about a wager?","TWN":"有自信的話，打個賭如何？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"좋아.","JPN":"いいわ。","ENG":"You're on.","TWN":"好啊。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"진 사람이 시장에 가서 맛있는 거 사오기!","JPN":"負けた人が市場でおいしいものを買ってくる！","ENG":"Loser goes to the market and buys something tasty!","TWN":"輸的人去市場買好吃的！"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"식사를 한지 얼마나 되었다고 벌써…","JPN":"食事したばかりなのに……","ENG":"We just ate and you're already–","TWN":"才吃完多久，怎麼又要…"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"잠깐…","JPN":"待ってくれ……","ENG":"Wait…","TWN":"等等…"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"항복하리다.","JPN":"降参だ。","ENG":"I surrender.","TWN":"我投降。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"항복? 벌써?","JPN":"降参？　もう？","ENG":"Surrender? Already?","TWN":"投降？這麼快？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"피하려다… 급소에 맞았소.","JPN":"避けようとして……急所に当たった。","ENG":"Tried to dodge… and got hit in a rather sensitive spot.","TWN":"本來想躲的… 卻被打中要害。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"앗, 미안! 괜찮아?","JPN":"あっ、ごめん！　大丈夫？","ENG":"Ah, sorry! Are you okay?!","TWN":"哎呀，抱歉！你還好嗎？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"저기… 내가 반칙패인 걸로 할까?","JPN":"その……私が反則負けしたことにする？","ENG":"Hey… should I just call it a foul on my part?","TWN":"那個… 不然算我犯規輸掉好了？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"항복이라고 했으니 내가 진 거요. 먹고 싶은 거나 말씀하시게.","JPN":"降参と言った某の負けだ。食べたいものを教えてくれ。","ENG":"I said I surrender, so I lost. Just tell me what you want.","TWN":"我已經說投降了，所以是我輸了。說說你想吃什麼吧。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그럼 곶감. 잘 익은 걸로.","JPN":"じゃあ干し柿。よく熟れたやつ。","ENG":"Then dried persimmons. Make sure they're perfectly ripe.","TWN":"那我要柿餅。要熟透的那種。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"금방 다녀오리다.","JPN":"すぐ帰ってくる。","ENG":"I'll be right back.","TWN":"我很快就回來。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"혼자 어딜 가려고? 나도 같이 갈래.","JPN":"一人で？　私も一緒に行くわ。","ENG":"Where do you think you're going alone? I'm coming too.","TWN":"你要一個人去哪裡？我也一起去。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"벌칙인데, 같이 가면 무슨 의미가 있는 거요?","JPN":"勝負に負けた罰なのに一緒に行っては何の意味もないではないか。","ENG":"It's a penalty. Wouldn't make sense if you came along.","TWN":"這是懲罰，一起去還有什麼意義呢？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신 옷 젖은 것 때문에 감기에 걸리면 나도 책임이 있는 거니까.","JPN":"雪合戦で濡れた服のせいで風邪を引かせてしまったら、私の責任だもの。","ENG":"If your coat's soaked and you catch a cold, that's on me too.","TWN":"你衣服濕了，如果感冒了，我也是有責任的。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"어때? 이렇게 하면 옷 금방 마르겠지?","JPN":"どう？　こうすればすぐ乾くでしょう。","ENG":"How's this? You'll dry off faster, right?","TWN":"如何？這樣衣服很快就乾了吧？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"시장까지 그대를 이렇게 업고 가란 말인가?","JPN":"市場までそなたを負ぶって行けということか？","ENG":"You expect me to carry you like this all the way to the market?","TWN":"你是要我這樣揹著你走到市場嗎？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"왜? 별로 안 따뜻해?","JPN":"何？　あまり温かくない？","ENG":"Why not? Not warm enough?","TWN":"怎麼？不溫暖嗎？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"따뜻하긴 하지만, 아무래도 무게가…","JPN":"温かいが、どうも重……","ENG":"You're warm, but not exactly lig–","TWN":"雖然溫暖，但是重量…"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"거기서 한 마디만 더 하면, 평생 후회하게 해줄 거야.","JPN":"それ以上言ったら、一生後悔させてあげるわよ。","ENG":"Say one more word and I'll make sure you regret it for life.","TWN":"你再多說一句，我會讓你後悔一輩子。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"서생, 나 손잡아줘.","JPN":"ショウ、手を繋いでちょうだい。","ENG":"Seosaeng. Hold my hand.","TWN":"書生，握住我的手。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_102"},{"id":"L46_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"손은 내 것보다 당신이 더 따뜻하니까.","JPN":"こっちはあなたのほうが温かいから。","ENG":"Yours are always warmer than mine.","TWN":"你的手比我的手更溫暖。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_103"},{"id":"L49_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"그럼, 출발하리다.","JPN":"では行こうか。","ENG":"Then let's go.","TWN":"那麼，出發吧。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"삼군문의 일원이 된 그날 이후로…","JPN":"三軍門の一員となったあの日から……","ENG":"From the moment I joined the Trivanguard…","TWN":"成為三軍門的一員後…"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"난 처음으로 내가 어떤 짐승에게 삶을 빼앗기고 있다는 사실을 알게 되었네.","JPN":"某は初めて、自分があるケモノに人生を奪われているという事実を知った。","ENG":"I realized for the first time that some Beast had been leeching the life out of me.","TWN":"我第一次意識到自己的人生正被某種野獸剝奪。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"범을 잡겠다 맹세하며 달려온 나날은… 참으로 기묘하였소.","JPN":"虎を倒すと誓いを立てて走り続けた日々は……実に奇妙なものであった。","ENG":"The days I swore I'd hunt the Tiger… It was a strange chapter of my life.","TWN":"發誓要抓住老虎的日子… 真是奇妙。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"지금껏 내가 겪어온 불운한 일들이… 그저 우연이 아닌 필연이었음을 깨달았을 때의 기분이란-","JPN":"今まで自分を襲った不幸が……単なる偶然ではなく、必然だったと知った時の気分……","ENG":"That all the misfortunes I endured weren't just chance… but a cruel inevitability….","TWN":"當我意識到至今為止經歷的那些不幸，並非偶然而是必然時，那種感覺…"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"오래도록 떠돌던 상실감이… 분노라는 또렷한 표상이 되어 한 점으로 나아갈 때의 맹렬함이란-","JPN":"長い間漂っていた喪失感が……怒りという鮮明な目印になり、一点に向かい猛烈に突き進むその感覚……","ENG":"When the long wandering loss turned into a clear, burning rage… I felt it drive me forward.","TWN":"長久以來漂泊的失落感，化為憤怒這個清晰的表象，並朝著某一點前進時的猛烈感…"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"실로 삶의 어느 때보다 굳세고… 또한 강렬하였지.","JPN":"人生のどの時期よりも屈強で……鮮烈だった。","ENG":"Stronger than ever before… Fiercer than I thought possible.","TWN":"這確實比我人生中的任何時候都更堅定、也更強烈。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"부서지기 전까지 단단한 바위처럼… 또한 바람에 날리는 불꽃처럼.","JPN":"硬すぎるゆえ壊れる岩のように……風に揺らぐ炎のように。","ENG":"Like a stone that held out till the end, only to shatter… Like a spark flung into the wind.","TWN":"就像在破碎前堅硬的岩石… 也像隨風飄揚的火焰。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"이것이로구나.","JPN":"これか。","ENG":"So this is it.","TWN":"就是這個了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"관리국이 한 번도 넘어서지 못한, 시간을 거스르는 힘을 가진 너의 역작이.","JPN":"管理局が一度も超えられなかった、時を遡る力を持つお前の力作は。","ENG":"Your magnum opus. The one thing the Administration could never replicate. A device that defies time itself.","TWN":"管理局從未超越過，擁有逆轉時間力量的你的傑作。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"명달 대장의 생각만큼 자유분방한 힘은 아닐 거요.","JPN":"アカタツ隊長が想像するほど自由の利く力ではないと思う。","ENG":"It's not as versatile as you might hope, Commander.","TWN":"這力量不像明達隊長想像的那麼自由。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"좌표를 임의로 정하는 것이 불가능하고, 동력의 한계를 넘어선 과거로도 갈 수 없으니.","JPN":"座標を任意に決めることはできず、動力の限界を超える過去には行けぬゆえ。","ENG":"I can't set the coordinates freely, and it won't go further than what its power source allows.","TWN":"無法任意設定座標，也無法前往超越動力極限的過去。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"그리고 다량의 이터니움, 내 피를 동력으로 삼아야 한다는 한계도 명확하지.","JPN":"それに大量のエタニウムと某の血を動力にしなければならないという限界もある。","ENG":"And there's still the matter of requiring large amounts of Eternium and my blood as fuel. A very real limit.","TWN":"而且需要大量的永恆石，以及我的血作為動力，這也是明顯的限制。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"하하, 겸손 떨 것 없다. 그 정도라도 해낼 사람이 너 말고 달리 누가 있을까?","JPN":"はは、謙遜しなくていい。お前を除いて、これほどの物が作れる人はいないのだからな。","ENG":"Haha, no need to downplay it. Honestly, who else could have pulled this off but you?","TWN":"哈哈哈，別謙虛了。除了你，還有誰能做到這種地步？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"이 발명품. 이름은 정했느냐?","JPN":"この発明品、名前は決めたか？","ENG":"So, have you given it a name?","TWN":"這個發明品，你取好名字了嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"…<color=#ffd34c>우.물</color>.","JPN":"…<color=#ffd34c>イド</color>。","ENG":"…Uh, <color=#ffd34c>Well</color>.","TWN":"…<color=#ffd34c>井</color>。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"우물이라. 생긴 것만큼 담백한 이름이로구만.","JPN":"井戸か。見た目どおりシンプルな名前だな。","ENG":"Well? Fits its modest look, I suppose.","TWN":"井嗎，和它的外形一樣樸實的名字。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"서생은 뭘 만들 건 의미 그대로 붙이고 그걸 멋대로 줄여서 부르거든요.","JPN":"ショウは何を作っても役割そのままの名前をつけて、勝手に略して呼ぶんです。","ENG":"Seosaeng always names things literally and then shortens them however he pleases.","TWN":"書生做事都是直接取其意義，然後隨便簡稱。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그 두 글자도 실은 엄청나게 긴 이름일 걸요?","JPN":"その2文字も、フルネームはものすごく長いに決まっています。","ENG":"That one syllable probably stands for some absurdly long title.","TWN":"這個字說不定也是很長的名字的縮寫呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"호오, 그런가? 무엇의 줄임말이지?","JPN":"ほお、そうなのか？　何の略なんだ？","ENG":"Oh? Then what's it short for?","TWN":"哦，是嗎？是什麼的縮寫？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"우물이라 함은…","JPN":"イドとは……","ENG":"Well stands for…","TWN":"井的意思是…"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"<color=#ffd34c>우리 운명을 바꾸어줄 물건.</color>","JPN":"<color=#ffd34c>いつか我らの運命を変えてくれるであろう道具。</color>","ENG":"<color=#ffd34c>Will to End the Locked Line</color>.","TWN":"<color=#ffd34c>能改變我們命運的東西。</color>"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"본인의 사사로운 바람을 담아, 그리 지었소.","JPN":"某の個人的な願望を込めて、そう名付けた。","ENG":"A name born of my own small wish.","TWN":"我將個人的小小心願寄託其中，所以取了這個名字。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"subtitle","speaker":null,"text":{"KOREA":"한 달 후, 노스텔지어 공방.","JPN":"1か月後、工房ノスタルジア","ENG":"One month later, Nostalgia Workshop.","TWN":"一個月後，追舊工作室"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"subtitle","speaker":null,"text":{"KOREA":"과거로 가기 위한 장치, 가동 예정일 D-0","JPN":"過去へ向かうための装置、稼働予定日当日","ENG":"Device to the Past activation day","TWN":"回到過去的裝置，預計啟動日D-day"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"신기해.","JPN":"不思議。","ENG":"Hard to believe, huh.","TWN":"真神奇。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"얼마 전만 해도 빈털터리였는데, 사부가 그 알파트릭스 회장님을 구한 덕에 필요한 걸 전부 장만하게 됐잖아.","JPN":"ちょっと前までは貧乏だったのに、師匠がアルファトリックスの会長を助けたおかげで必要なものが全部手に入っちゃった。","ENG":"Just a while ago we had nothing. Now, thanks to saving the President of Alphatrix, we've got everything we need.","TWN":"不久前我還一無所有，托師父拯救阿爾法崔克斯會長的福，我現在什麼都能買。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이런 게 운명의 장난이란 걸까?","JPN":"これが運命のいたずらってやつなのかな。","ENG":"Is this what people mean when they say fate works in strange ways?","TWN":"這就是命運的惡作劇嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"장난을 쳐도 운명이란 것이지.","JPN":"いたずらさえも、所詮は運命の内だということだ。","ENG":"Strange or not, it's still fate.","TWN":"就算開玩笑，這也是命運。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"어떤 선택을 해도 그것이 운명일 테니. 우린 그걸 활용하기만 하면 되는 걸세.","JPN":"どんな選択をしようと、もうそれ自体が運命に他ならない。我らはそれを利用しさえすればよい。","ENG":"No matter the choice, it's still written. All we can do is make use of it.","TWN":"無論做出什麼選擇，那都會是命運。我們只需要加以利用就好。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"네, 네- 농담은 할 줄 몰라도 누구보다 운명을 잘 아시는 분의 말씀이니 맞겠죠.","JPN":"はい、はい。冗談は下手でも誰よりも運命に詳しい人のことだし、多分その通りでしょ。","ENG":"Yeah, yeah. Coming from someone who can't tell a joke but knows everything about fate, I guess that's legit.","TWN":"是，是— 雖然不懂得開玩笑，但你是比誰都了解命運的人，所以你說的對。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그나저나 우리 <color=#ffd34c>과.위.장</color>. 디자인 많이 바뀌었네.","JPN":"それにしても、うちの<color=#ffd34c>過向装</color>……デザインもかなり変わったね。","ENG":"By the way, our <color=#ffd34c>DTP</color> looks totally different now.","TWN":"話說，我們<color=#ffd34c>回裝置</color>的設計變了很多呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이젠 첨단장비라기 보단 고대 유물 같달까.","JPN":"今じゃ最新装備というよりは古代遺物って感じ。","ENG":"Less like high-tech gear and more like ancient relic vibes.","TWN":"與其說是尖端設備，不如說是古代遺物。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"돌아온 관리국 시절의 기억을 토대로 장치의 안정성을 개선해본 걸세.","JPN":"取り戻した管理局所属の頃の記憶を元に、装置の安全性を改善してみたのだ。","ENG":"I reworked the design using the memories I recovered from my time at the Administration. Stability was the priority.","TWN":"我根據回到管理局時期的記憶，改善了裝置的穩定性。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이 동앗줄이란 것을 장치와 연결해두면, 차원폭풍에 휩쓸려도 길을 잃지 않게 되지.","JPN":"この縄を装置に繋いでおくと、次元の暴風に巻き込まれても道に迷わずに済む。","ENG":"If I connect the Tether to the device, even if we're swept into a dimensional storm, we won't lose our way.","TWN":"只要將這條繩索和裝置連接，即使被次元風暴捲入，也不會迷路。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"동앗줄은 무슨 줄임말인데?","JPN":"縄は何の略なの？","ENG":"Does Tether stand for anything?","TWN":"那繩索又是什麼的縮寫？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"동앗줄은 동앗줄이지.","JPN":"縄は縄だ。","ENG":"It's just a rope. That's all.","TWN":"繩索就是繩索。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"흐음- 웬일로 이번엔 줄임말이 아니네.","JPN":"へえ～珍しく略語じゃないんだ。","ENG":"Huh. No abbreviation this time? That's new.","TWN":"嗯— 難得這次不是縮寫。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"앤디.","JPN":"アンディー。","ENG":"Andy.","TWN":"安狄。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Yeah?","TWN":"嗯？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"아직 늦지 않으니 잘 생각해보게.","JPN":"まだ間に合う。よく考えてみたまえ。","ENG":"It's not too late. You should still think this through.","TWN":"還來得及，你再好好想想。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나에겐 과거로 가야만 할 이유가 있지만, 그대는 그렇지 않아.","JPN":"某には過去に戻らねばならない理由があるが、そなたは違う。","ENG":"I have a reason I need to go back. But you don't.","TWN":"我有必須回到過去的理由，但你沒有。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이런 일로 목숨을 걸기에 그대는 아직…","JPN":"このようなことで命を懸けるには、そなたはまだ……","ENG":"Risking your life for this is–","TWN":"為這種事賭上性命，你還…"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"또 그런다, 사부.","JPN":"師匠。","ENG":"Master.","TWN":"師父。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"챔버에서 그날, 사부가 바이크를 타고 나타나지 않았으면 난 죽었어.","JPN":"あの日、チェンバーで師匠がバイクに乗って現れてくれなかたら、私は死んでたよ。","ENG":"If you hadn't shown up on your bike that day in Chamber, I'd be dead.","TWN":"那天在房間裡，如果師父沒有騎著摩托車出現，我早就死了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"세상에 운명이란 게 있다면, 난 지금 사부를 돕기 위해서 살아있는 거야.","JPN":"この世に運命ってものがあるなら、今の私は師匠を手伝うために生きてる。","ENG":"If fate's real, then I'm alive today to help you. That's my reason.","TWN":"如果世界上有命運這種東西，那我現在活著就是為了幫助師父。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그리고 이번엔 사부가 동앗줄이란 것도 만들었잖아? 여차하면, 사부 말처럼 이게 내 목숨을 구해주겠지.","JPN":"それに、今回は師匠が縄ってのも作ってくれたでしょ？　いざとなったら、師匠の言ったとおり、これが私を助けてくれるよ。","ENG":"And now you made the Tether. If things go sideways, maybe it'll save me too.","TWN":"而且這次師父也做了繩索不是嗎？萬一有事，就像師父說的那樣，它會救我的命。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"설득은 끝났나?","JPN":"説得は終わったか？","ENG":"Done trying to convince her?","TWN":"說服完了嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…그래.","JPN":"……ああ。","ENG":"…Yes.","TWN":"…好。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"셋 모두 들어가게 됐네.","JPN":"3人全員で入ることになった。","ENG":"All three of us are going in.","TWN":"我們三個人都進去吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"준비는 됐나, 앤디?","JPN":"準備はいいか、アンディー？","ENG":"Ready, Andy?","TWN":"準備好了嗎，安狄？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"응! 점검 끝났어!","JPN":"うん！　点検も終わった！","ENG":"Yup! Systems check complete!","TWN":"嗯！檢查完畢！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_05"},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"가보자. 과거를 바꾸러.","JPN":"行こう。過去を変えてみせるんだ！","ENG":"Let's go and change the past.","TWN":"走吧。讓我們去改變過去。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};